import {
  createContext,
  useState,
  useEffect,
  useCallback,
  useMemo,
} from "react";
import type { ReactNode } from "react";
import {
  type ThemeMode,
  getStoredTheme,
  storeTheme,
  applyTheme,
  resolveTheme,
} from "../lib/theme";
import {
  type ThemeWidgetConfig,
  type ResolvedConfig,
  resolveConfig,
} from "../lib/config";

export interface ThemeContextType {
  mode: ThemeMode;
  resolved: "light" | "dark";
  setTheme: (mode: ThemeMode) => void;
  config: ResolvedConfig;
}

export const ThemeContext = createContext<ThemeContextType | null>(null);

interface ThemeProviderProps {
  children: ReactNode;
  config?: ThemeWidgetConfig;
}

function ThemeProviderInner({
  children,
  config: userConfig,
}: ThemeProviderProps) {
  const resolvedConfig = useMemo(
    () => resolveConfig(userConfig),
    [userConfig]
  );

  const [mode, setMode] = useState<ThemeMode>(() => {
    if (typeof window === "undefined") return resolvedConfig.defaultMode;
    return getStoredTheme(resolvedConfig.storageKey);
  });

  const [resolved, setResolved] = useState<"light" | "dark">(() =>
    resolveTheme(mode)
  );

  useEffect(() => {
    applyTheme(mode);
    setResolved(resolveTheme(mode));
  }, [mode]);

  useEffect(() => {
    const mql = window.matchMedia?.("(prefers-color-scheme: dark)");
    if (!mql) return;

    const onChange = () => {
      if (getStoredTheme(resolvedConfig.storageKey) === "system") {
        applyTheme("system");
        setResolved(resolveTheme("system"));
      }
    };

    mql.addEventListener("change", onChange);
    return () => mql.removeEventListener("change", onChange);
  }, [resolvedConfig.storageKey]);

  const setTheme = useCallback(
    (next: ThemeMode) => {
      setMode(next);
      storeTheme(resolvedConfig.storageKey, next);
      applyTheme(next);
      setResolved(resolveTheme(next));
    },
    [resolvedConfig.storageKey]
  );

  const contextValue = useMemo<ThemeContextType>(
    () => ({ mode, resolved, setTheme, config: resolvedConfig }),
    [mode, resolved, setTheme, resolvedConfig]
  );

  return (
    <ThemeContext.Provider value={contextValue}>
      {children}
    </ThemeContext.Provider>
  );
}

ThemeProviderInner.displayName = "ThemeProvider";

export const ThemeProvider = ThemeProviderInner;
