import type { ThemeMode } from "./theme";

export interface ThemeWidgetConfig {
  position?: "bottom-left" | "bottom-right" | "top-left" | "top-right";
  brandColors?: {
    primary?: string;
    secondary?: string;
    accent?: string;
  };
  launcher?: {
    size?: "sm" | "md" | "lg";
    tooltip?: string;
    zIndex?: number;
  };
  panel?: {
    title?: string;
  };
  storageKey?: string;
  defaultMode?: ThemeMode;
}

export interface ResolvedConfig {
  position: "bottom-left" | "bottom-right" | "top-left" | "top-right";
  brandColors: {
    primary: string;
    secondary: string;
    accent: string;
  };
  launcher: {
    size: "sm" | "md" | "lg";
    tooltip: string;
    zIndex: number;
  };
  panel: {
    title: string;
  };
  storageKey: string;
  defaultMode: ThemeMode;
}

const DEFAULT_CONFIG: ResolvedConfig = {
  position: "bottom-left",
  brandColors: {
    primary: "#0d9488",
    secondary: "#1e3a5f",
    accent: "#f59e0b",
  },
  launcher: {
    size: "md",
    tooltip: "Theme",
    zIndex: 9998,
  },
  panel: {
    title: "Choose Theme",
  },
  storageKey: "theme-mode",
  defaultMode: "system",
};

export function resolveConfig(
  userConfig?: ThemeWidgetConfig
): ResolvedConfig {
  if (!userConfig) return { ...DEFAULT_CONFIG };

  return {
    position: userConfig.position ?? DEFAULT_CONFIG.position,
    brandColors: {
      ...DEFAULT_CONFIG.brandColors,
      ...userConfig.brandColors,
    },
    launcher: {
      ...DEFAULT_CONFIG.launcher,
      ...userConfig.launcher,
    },
    panel: {
      ...DEFAULT_CONFIG.panel,
      ...userConfig.panel,
    },
    storageKey: userConfig.storageKey ?? DEFAULT_CONFIG.storageKey,
    defaultMode: userConfig.defaultMode ?? DEFAULT_CONFIG.defaultMode,
  };
}
