import { useRef, useEffect } from "react";
import { motion } from "framer-motion";
import { X, Monitor, Sun, Moon } from "lucide-react";
import { useTheme } from "../hooks/useTheme";
import { ThemeOption } from "./ThemeOption";
import { cn } from "../lib/utils";

interface ThemePanelProps {
  onClose: () => void;
}

function ThemePanelInner({ onClose }: ThemePanelProps) {
  const { mode, setTheme, config } = useTheme();
  const panelRef = useRef<HTMLDivElement>(null);
  const closeRef = useRef<HTMLButtonElement>(null);
  const { position, panel: panelConfig } = config;

  useEffect(() => {
    closeRef.current?.focus();
  }, []);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        onClose();
        return;
      }
      if (e.key === "Tab") {
        const el = panelRef.current;
        if (!el) return;
        const focusable = el.querySelectorAll<HTMLElement>(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        if (focusable.length === 0) return;
        const first = focusable[0]!;
        const last = focusable[focusable.length - 1]!;
        if (e.shiftKey && document.activeElement === first) {
          e.preventDefault();
          last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const positionClasses = cn(
    "theme-widget-panel",
    position.includes("bottom") && "theme-widget-panel--bottom",
    position.includes("top") && "theme-widget-panel--top",
    position.includes("left") && "theme-widget-panel--left",
    position.includes("right") && "theme-widget-panel--right"
  );

  const yDirection = position.includes("bottom") ? 20 : -20;

  const prefersReduced =
    typeof window !== "undefined"
      ? window.matchMedia("(prefers-reduced-motion: reduce)").matches
      : false;

  return (
    <>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        transition={prefersReduced ? { duration: 0 } : { duration: 0.15 }}
        className="theme-widget-backdrop"
        style={{ zIndex: config.launcher.zIndex }}
        onClick={onClose}
        aria-hidden="true"
      />
      <motion.div
        ref={panelRef}
        role="dialog"
        aria-modal="true"
        aria-label={panelConfig.title}
        initial={
          prefersReduced ? false : { opacity: 0, y: yDirection, scale: 0.96 }
        }
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={
          prefersReduced
            ? { opacity: 0 }
            : { opacity: 0, y: yDirection * 0.66, scale: 0.97 }
        }
        transition={
          prefersReduced
            ? { duration: 0 }
            : { duration: 0.2, ease: [0.25, 0.46, 0.45, 0.94] }
        }
        className={positionClasses}
        style={{
          zIndex: config.launcher.zIndex + 1,
          "--theme-primary": config.brandColors.primary,
          "--theme-secondary": config.brandColors.secondary,
          "--theme-accent": config.brandColors.accent,
        } as React.CSSProperties}
      >
        <div className="theme-widget-panel-header">
          <h2 className="theme-widget-panel-title">{panelConfig.title}</h2>
          <button
            ref={closeRef}
            type="button"
            onClick={onClose}
            className="theme-widget-close-btn"
            aria-label="Close theme options"
          >
            <X className="theme-widget-close-icon" aria-hidden="true" />
          </button>
        </div>

        <div
          className="theme-widget-panel-body"
          role="radiogroup"
          aria-label="Theme selection"
        >
          <ThemeOption
            icon={<Monitor className="theme-widget-icon" />}
            label="System"
            description="Match your device settings"
            active={mode === "system"}
            onSelect={() => setTheme("system")}
          />
          <ThemeOption
            icon={<Sun className="theme-widget-icon" />}
            label="Light"
            description="Bright and airy appearance"
            active={mode === "light"}
            onSelect={() => setTheme("light")}
          />
          <ThemeOption
            icon={<Moon className="theme-widget-icon" />}
            label="Dark"
            description="Easy on the eyes at night"
            active={mode === "dark"}
            onSelect={() => setTheme("dark")}
          />
        </div>
      </motion.div>
    </>
  );
}

ThemePanelInner.displayName = "ThemePanel";

export const ThemePanel = ThemePanelInner;
